import{_ as a,c as t,o as i,ah as n}from"./chunks/framework.C-x9UAyH.js";const k=JSON.parse('{"title":"Funciones anidadas","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"oracle/funciones_fila/funciones_anidadas.md","filePath":"oracle/funciones_fila/funciones_anidadas.md","lastUpdated":1736202388000}'),e={name:"oracle/funciones_fila/funciones_anidadas.md"};function d(r,s,l,p,o,h){return i(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="funciones-anidadas" tabindex="-1">Funciones anidadas <a class="header-anchor" href="#funciones-anidadas" aria-label="Permalink to &quot;Funciones anidadas&quot;">​</a></h1><p>Las funciones anidadas en Oracle se refieren al uso de una función SQL dentro de otra. Esto permite realizar transformaciones o cálculos más complejos en una única instrucción.</p><p>Oracle evalúa primero las funciones más internas y luego las externas.</p><p>Se pueden usar diferentes tipos de funciones, como funciones de conversión, de manejo de cadenas, matemáticas, de agrupación, entre otras.</p><p><strong>TABLE EMPLOYEES</strong></p><table tabindex="0"><thead><tr><th>last_name</th><th>department_id</th></tr></thead><tbody><tr><td>Taylor</td><td>10</td></tr><tr><td>King</td><td>20</td></tr><tr><td>Adams</td><td>30</td></tr><tr><td>Green</td><td>40</td></tr><tr><td>Peterson</td><td>50</td></tr><tr><td>Brown</td><td>60</td></tr></tbody></table><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> last_name,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        department_id, </span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        UPPER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CONCAT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(SUBSTR(last_name, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;_chile&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)) resultado</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> employees</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> department_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">between</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 40</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>La función <strong>SUBSTR</strong> retorna los primeros seis caracteres del apellido del empleado. La función <strong>CONCAT</strong> concatena el resultado de la función SUBSTR con el string &#39;_chile&#39;. Finalmente la función <strong>UPPER</strong> convierte en mayúscula el resultado entregado por la función CONCAT.</p><table tabindex="0"><thead><tr><th>last_name</th><th>department_id</th><th>resultado</th></tr></thead><tbody><tr><td>Taylor</td><td>10</td><td>TAYLOR_CHILE</td></tr><tr><td>King</td><td>20</td><td>KING_CHILE</td></tr><tr><td>Adams</td><td>30</td><td>ADAMS_CHILE</td></tr><tr><td>Green</td><td>40</td><td>GREEN_CHILE</td></tr></tbody></table>`,9)])])}const E=a(e,[["render",d]]);export{k as __pageData,E as default};
